// PNG download - uses Object URL for SVG charts, avoids CSP-blocked data URIs
function downloadPNG(id,fn){const el=document.getElementById(id);if(!el)return;const svgs=el.querySelectorAll("svg");const rect=el.getBoundingClientRect();const s=2;const cv=document.createElement("canvas");cv.width=rect.width*s;cv.height=rect.height*s;const ctx=cv.getContext("2d");ctx.scale(s,s);ctx.fillStyle="#ECE9F1";ctx.fillRect(0,0,rect.width,rect.height);
el.querySelectorAll("[style]").forEach(card=>{const cs=window.getComputedStyle(card);if(cs.backgroundColor&&cs.backgroundColor!=="rgba(0, 0, 0, 0)"&&cs.backgroundColor!=="transparent"){const cr=card.getBoundingClientRect();const x=cr.left-rect.left,y=cr.top-rect.top;ctx.fillStyle=cs.backgroundColor;const br=parseInt(cs.borderRadius)||0;if(br>0){ctx.beginPath();ctx.roundRect(x,y,cr.width,cr.height,br);ctx.fill()}else ctx.fillRect(x,y,cr.width,cr.height)}});
el.querySelectorAll("span,p,h1,h2,h3,h4,h5,div,td,th").forEach(te=>{const cs=window.getComputedStyle(te);if(te.children.length===0||te.tagName==="SPAN"||te.tagName==="TD"||te.tagName==="TH"){const t=te.textContent;if(!t?.trim())return;const tr=te.getBoundingClientRect();if(!tr.width||!tr.height)return;ctx.font=`${cs.fontWeight} ${cs.fontSize} ${cs.fontFamily}`;ctx.fillStyle=cs.color;ctx.textBaseline="top";ctx.fillText(t.trim(),tr.left-rect.left,tr.top-rect.top+2,tr.width)}});
let pending=svgs.length;if(!pending){const l=document.createElement("a");l.download=fn+".png";l.href=cv.toDataURL("image/png");l.click();return}
svgs.forEach(svg=>{const sr=svg.getBoundingClientRect();const x=sr.left-rect.left,y=sr.top-rect.top;const cl=svg.cloneNode(true);cl.setAttribute("xmlns","http://www.w3.org/2000/svg");const aE=svg.querySelectorAll("*");const cE=cl.querySelectorAll("*");aE.forEach((e,i)=>{if(cE[i]){const cs=window.getComputedStyle(e);["fill","stroke","stroke-width","font-size","font-family","font-weight","text-anchor","dominant-baseline","opacity"].forEach(p=>{const v=cs.getPropertyValue(p);if(v)cE[i].style.setProperty(p,v)})}});
const blob=new Blob([new XMLSerializer().serializeToString(cl)],{type:"image/svg+xml;charset=utf-8"});const url=URL.createObjectURL(blob);const img=new window.Image();img.onload=()=>{ctx.drawImage(img,x,y,sr.width,sr.height);URL.revokeObjectURL(url);pending--;if(!pending){const l=document.createElement("a");l.download=fn+".png";l.href=cv.toDataURL("image/png");l.click()}};img.onerror=()=>{pending--;if(!pending){const l=document.createElement("a");l.download=fn+".png";l.href=cv.toDataURL("image/png");l.click()}};img.src=url})}

function downloadCSVData(h,rows,fn){const dq=/"/g;const csv=[h.join(","),...rows.map(r=>r.map(v=>{const s=(v||"").toString().replace(dq,'""');return '"'+s+'"'}).join(","))].join("\n");const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([csv],{type:"text/csv"}));a.download=fn+".csv";a.click()}

// Parsers
function parseCSV(text){const lines=[];let cur="",inQ=false;for(let i=0;i<text.length;i++){const c=text[i];if(c==='"'){inQ=!inQ;continue}if(c==='\n'&&!inQ){lines.push(cur);cur="";continue}if(c==='\r'&&!inQ)continue;cur+=c}if(cur)lines.push(cur);if(lines.length<2)return[];const hdrs=lines[0].split(",").map(h=>h.trim());return lines.slice(1).filter(l=>l.trim()).map(line=>{const vals=[];let v="",q=false;for(let i=0;i<line.length;i++){if(line[i]==='"'){q=!q;continue}if(line[i]===','&&!q){vals.push(v.trim());v="";continue}v+=line[i]}vals.push(v.trim());const obj={};hdrs.forEach((h,i)=>{obj[h]=vals[i]||""});return obj})}
function isMailchimpReport(text){return text.trim().split(/\r?\n/).slice(0,5).join("\n").toLowerCase().includes("email campaign report")}
function parseMailchimpReport(text){const lines=text.split(/\r?\n/).map(l=>l.trim()).filter(Boolean);const kv={};const uc=[];let inU=false;for(const line of lines){const parts=[];let c="",q=false;for(let i=0;i<line.length;i++){if(line[i]==='"'){q=!q;continue}if(line[i]===','&&!q){parts.push(c.trim());c="";continue}c+=line[i]}parts.push(c.trim());if(parts[0]?.toLowerCase()==="clicks by url"){inU=true;continue}if(parts[0]?.toLowerCase()==="url")continue;if(inU&&parts[0]?.startsWith("http")){uc.push({url:parts[0],totalClicks:parseInt((parts[1]||"0").replace(/,/g,""),10),uniqueClicks:parseInt((parts[2]||"0").replace(/,/g,""),10)});continue}if(parts.length>=2&&parts[0]?.endsWith(":")){kv[parts[0].replace(/:$/,"").trim().toLowerCase()]=parts[1]}}const eN=v=>{if(!v)return 0;const m=String(v).replace(/,/g,"").match(/^\d+/);return m?parseInt(m[0],10):0};const eP=v=>{if(!v)return 0;const m=String(v).match(/\(([\d.]+)%\)/);return m?parseFloat(m[1]):0};return{title:kv["title"]||"",subjectLine:kv["subject line"]||"",date:kv["delivery date/time"]||"",sends:eN(kv["total recipients"]),delivered:eN(kv["successful deliveries"]),bounces:eN(kv["bounces"]),opens:eN(kv["recipients who opened"]),totalOpens:eN(kv["total opens"]),clicks:eN(kv["recipients who clicked"]),totalClicks:eN(kv["total clicks"]),unsubs:eN(kv["total unsubs"]),openRate:eP(kv["recipients who opened"]),clickRate:eP(kv["recipients who clicked"]),bounceRate:eP(kv["bounces"]),urlClicks:uc,_isMailchimpReport:true}}

function isPubCommsCSV(text){const h=text.trim().split(/\r?\n/)[0]?.toLowerCase()||"";return h.includes("serial number")&&h.includes("campaign")&&h.includes("date sent")}

function parsePubCommsCSV(rows){return rows.map(row=>{const keys=Object.keys(row);const f=pats=>keys.find(k=>pats.some(p=>k.toLowerCase().includes(p)))||null;const pctStr=v=>{if(!v)return 0;const n=parseFloat(String(v).replace("%",""));return isNaN(n)?0:n};const numStr=v=>{if(!v)return 0;return parseInt(String(v).replace(/,/g,""),10)||0};return{name:row[f(["campaign"])]||"",date:row[f(["date sent"])]||"",sends:numStr(row[f(["emails sent"])]),opens:numStr(row[f(["email opened"])]),openRate:pctStr(row[f(["email open rate","open rate"])]),clicks:numStr(row[f(["email clicked"])]),clickRate:pctStr(row[f(["email click rate","click rate"])]),totalClicks:numStr(row[f(["email total clicks"])]),bounces:numStr(row[f(["email bounces","bounces"])]),bounceRate:pctStr(row[f(["email bounce rate","bounce rate"])]),unsubs:numStr(row[f(["email unsubscribes","unsubscribes"])]),unsubRate:pctStr(row[f(["email unsubscribe rate"])])}}).filter(r=>r.name)}

function cleanVal(v){if(!v||v==="#REF!"||v==="N/A"||v==="#N/A"||v==="\u2014"||v==="\u2013"||v==="-"||v==="Unknown"||v==="\u0087")return"";return v.trim()}
function mapClickerRow(row){const keys=Object.keys(row);const f=pats=>{const k=keys.find(k=>{const lk=k.toLowerCase().trim();return pats.some(p=>lk===p||lk.includes(p))});return k?cleanVal(row[k]):""};return{email:f(["email address","email"]),firstName:f(["first name"]),lastName:f(["last name"]),accountName:f(["account name"]),company:f(["company"])||f(["account name"]),demandAccountType:f(["demand account type"]),holdingCompany:f(["holding company"]),demandAccountStatus:f(["demand account status"]),region:f(["region"]),accountOwner:f(["account owner"]),careerLevel:f(["career-level","career level","seniority"]),department:f(["department"]),contactType:f(["contact type"]),country:f(["country"]),state:f(["state"]),city:f(["city"]),predictedGender:f(["predicted gender"]),predictedAge:f(["predicted age"]),statusSupply:f(["status - supply"]),teamSupply:f(["team - supply"]),teamLeadSupply:f(["team lead - supply"]),timeClicked:f(["time","click time","timestamp"]),linkClicked:f(["link","url","clicked url"]),fullName:f(["full name"])}}

function parseDate(d){if(!d)return null;const s=String(d).replace(/,/g,"").trim();let dt=new Date(s);if(!isNaN(dt))return dt;const parts=s.match(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})/);if(parts){const y=parts[3].length===2?"20"+parts[3]:parts[3];dt=new Date(`${parts[1]}/${parts[2]}/${y}`);if(!isNaN(dt))return dt}return null}

// UI Components
const Badge=({children,color=C.primary})=><span style={{display:"inline-flex",alignItems:"center",padding:"2px 8px",borderRadius:18,fontSize:10,fontWeight:600,background:color+"18",color,letterSpacing:.2}}>{children}</span>;
const KPI=({label,value,sub,icon:I,color=C.primary})=><div style={{background:C.white,borderRadius:16,padding:"20px 18px",boxShadow:"0 1px 3px rgba(0,0,0,.06)",border:"1px solid #f0ecf4",position:"relative",overflow:"hidden"}}><div style={{position:"absolute",top:-10,right:-10,width:70,height:70,borderRadius:"50%",background:color+"0a"}}/><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><div style={{width:32,height:32,borderRadius:8,background:color+"14",display:"flex",alignItems:"center",justifyContent:"center"}}><I size={16} color={color}/></div><span style={{fontSize:11,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:.6}}>{label}</span></div><div style={{fontSize:26,fontWeight:700,color:C.dark,lineHeight:1}}>{value}</div>{sub&&<div style={{fontSize:11,color:C.muted,marginTop:5}}>{sub}</div>}</div>;
const DlBtn=({id,name})=><button onClick={()=>downloadPNG(id,name)} title="Download PNG" style={{display:"flex",alignItems:"center",gap:3,padding:"4px 8px",background:"#f5f2f8",border:"1px solid #e8e4ee",borderRadius:6,fontSize:10,cursor:"pointer",color:C.muted,fontWeight:600}}><Download size={11}/> PNG</button>;
const CC=({title,children,actions,id})=><div id={id} style={{background:C.white,borderRadius:14,padding:20,border:"1px solid #f0ecf4"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14,gap:8,flexWrap:"wrap"}}><h4 style={{fontSize:13,fontWeight:700,color:C.dark}}>{title}</h4><div style={{display:"flex",gap:6,alignItems:"center"}}>{actions}{id&&<DlBtn id={id} name={typeof title==="string"?title.replace(/[^a-zA-Z0-9]/g,"_"):id}/>}</div></div>{children}</div>;
const Empty=({msg})=><div style={{textAlign:"center",padding:"60px 20px"}}><div style={{width:64,height:64,borderRadius:"50%",background:C.bg3+"60",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px"}}><FileText size={28} color={C.muted}/></div><p style={{fontSize:14,color:C.muted,fontWeight:500}}>{msg}</p></div>;
const Sel=({value,onChange,options,placeholder,style:s})=><select value={value} onChange={e=>onChange(e.target.value)} style={{padding:"8px 12px",borderRadius:8,border:"1px solid #e8e4ee",fontSize:12,outline:"none",background:"#fff",...s}}>{placeholder&&<option value="">{placeholder}</option>}{options.map(o=>typeof o==="string"?<option key={o} value={o}>{o}</option>:<option key={o.value} value={o.value}>{o.label}</option>)}</select>;
const DropZone=({label,onFile,loaded,count,accept=".csv"})=>{const ref=useRef(null);return <div onDragOver={e=>{e.preventDefault()}} onDrop={e=>{e.preventDefault();if(e.dataTransfer.files[0])onFile(e.dataTransfer.files[0])}} onClick={()=>ref.current?.click()} style={{border:`2px dashed ${loaded?C.success:"#ddd"}`,borderRadius:12,padding:"22px 20px",textAlign:"center",cursor:"pointer",background:loaded?C.success+"08":"#faf8fc"}}><input ref={ref} type="file" accept={accept} style={{display:"none"}} onChange={e=>e.target.files[0]&&onFile(e.target.files[0])}/>{loaded?<><CheckCircle size={20} color={C.success} style={{marginBottom:4}}/><p style={{fontSize:12,fontWeight:600,color:C.success}}>{label} - {count} rows</p></>:<><Upload size={20} color={C.muted} style={{marginBottom:4}}/><p style={{fontSize:12,fontWeight:600,color:C.dark}}>{label}</p><p style={{fontSize:10,color:C.muted,marginTop:2}}>Drag and drop or click</p></>}</div>};

function ListPicker({campaignType,value,onChange}){const[manual,setManual]=useState(false);const[mv,setMv]=useState("");const pre=PREDEFINED_LISTS[campaignType]||[];if(!pre.length||manual)return <div style={{display:"flex",gap:8}}><input value={manual?mv:value} onChange={e=>{setMv(e.target.value);onChange(e.target.value)}} placeholder="Enter list name..." style={{flex:1,padding:"10px 14px",borderRadius:10,border:"1px solid #e8e4ee",fontSize:13,outline:"none"}}/>{pre.length>0&&<button onClick={()=>{setManual(false);onChange("")}} style={{padding:"8px 12px",background:"#f5f2f8",border:"none",borderRadius:8,fontSize:11,cursor:"pointer",color:C.muted}}>Back</button>}</div>;return <div style={{display:"flex",gap:8}}><select value={value} onChange={e=>onChange(e.target.value)} style={{flex:1,padding:"10px 14px",borderRadius:10,border:"1px solid #e8e4ee",fontSize:13,outline:"none",background:"#fff"}}><option value="">Select list...</option>{pre.map(l=><option key={l} value={l}>{l}</option>)}</select><button onClick={()=>setManual(true)} style={{padding:"8px 12px",background:C.secondary+"12",border:"1px solid "+C.secondary+"30",borderRadius:8,fontSize:11,cursor:"pointer",color:C.secondary,fontWeight:600,whiteSpace:"nowrap"}}>+ Custom</button></div>}

// ========= MAIN APP =========
export default function App(){
  const[tab,setTab]=useState(0);const[campaigns,setCampaigns]=useState([]);const[clickers,setClickers]=useState([]);const[emailVisuals,setEmailVisuals]=useState([]);const[notes,setNotes]=useState({});const[loading,setLoading]=useState(true);const[showUpload,setShowUpload]=useState(false);const[generating,setGenerating]=useState(false);const[showSettings,setShowSettings]=useState(false);const[aiConfig,setAiConfig]=useState({provider:"anthropic",apiKey:"",ollamaUrl:"http://localhost:11434",ollamaModel:"llama3"});

  useEffect(()=>{(async()=>{const d=await loadData();if(d){setCampaigns(d.campaigns||[]);setClickers(d.clickers||[]);setEmailVisuals(d.emailVisuals||[]);setNotes(d.notes||{});if(d.aiConfig)setAiConfig(d.aiConfig)}setLoading(false)})()},[]);
  const persist=useCallback(async(c,cl,ev,n,ac)=>{await saveData({campaigns:c,clickers:cl,emailVisuals:ev,notes:n,aiConfig:ac||aiConfig})},[aiConfig]);

  const addCampaign=(camp)=>{const next=[...campaigns];const ex=next.findIndex(c=>c.name===camp.name&&c.type===camp.type&&c.listName===camp.listName);if(ex>=0){const e=next[ex];e.sends=(e.sends||0)+(camp.sends||0);e.opens=(e.opens||0)+(camp.opens||0);e.clicks=(e.clicks||0)+(camp.clicks||0);e.bounces=(e.bounces||0)+(camp.bounces||0);e.unsubs=(e.unsubs||0)+(camp.unsubs||0);if(camp.openRate)e.openRate=camp.openRate;if(camp.clickRate)e.clickRate=camp.clickRate;if(camp.bounceRate)e.bounceRate=camp.bounceRate;if(camp.subjectLine)e.subjectLine=camp.subjectLine;if(camp.date)e.date=camp.date;next[ex]=e}else{next.push({...camp,id:Date.now().toString()+Math.random().toString(36).slice(2,6)})}setCampaigns(next);persist(next,clickers,emailVisuals,notes)};
  const removeCampaign=(id)=>{const camp=campaigns.find(c=>c.id===id);const nC=campaigns.filter(c=>c.id!==id);const nCl=camp?clickers.filter(c=>!(c.campaignName===camp.name&&c.listName===camp.listName)):clickers;setCampaigns(nC);setClickers(nCl);persist(nC,nCl,emailVisuals,notes)};
  const addClickers=(nc,cn,ln)=>{const d=[...clickers];nc.forEach(n=>{if(!n.email)return;if(!d.find(x=>x.email===n.email&&x.campaignName===cn&&x.listName===ln))d.push({...n,campaignName:cn,listName:ln})});setClickers(d);persist(campaigns,d,emailVisuals,notes)};

  const generateNotes=async(camp)=>{setGenerating(true);try{const cc=clickers.filter(c=>c.campaignName===camp.name);const prompt=`Analyze this email campaign:\nCampaign: ${camp.name}\nType: ${camp.type}\nList: ${camp.listName}\nSubject: ${camp.subjectLine||"N/A"}\nDate: ${camp.date}\nSends: ${camp.sends}, Opens: ${camp.opens} (${camp.openRate?.toFixed(1)}%), Clicks: ${camp.clicks} (${camp.clickRate?.toFixed(1)}%), Bounces: ${camp.bounces}, Unsubs: ${camp.unsubs}\nClickers: ${cc.length}\nTop companies: ${[...new Set(cc.map(c=>c.company).filter(Boolean))].slice(0,10).join(", ")}\n\nReturn JSON only, no markdown: {"summary":"2-3 sentences","trends":["t1","t2","t3"],"recommendations":["r1","r2","r3"]}`;let text="";if(aiConfig.provider==="ollama"){const r=await fetch(`${aiConfig.ollamaUrl}/api/generate`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:aiConfig.ollamaModel,prompt,stream:false})});const d=await r.json();text=d.response||""}else{const h={"Content-Type":"application/json"};if(aiConfig.apiKey)h["x-api-key"]=aiConfig.apiKey;const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:h,body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})});const d=await r.json();text=d.content?.map(c=>c.text||"").join("")||""}const cl=text.replace(/```json|```/g,"").trim();const jm=cl.match(/\{[\s\S]*\}/);const parsed=JSON.parse(jm?jm[0]:cl);const nn={...notes,[camp.id]:parsed};setNotes(nn);persist(campaigns,clickers,emailVisuals,nn)}catch(err){console.error(err);const fb={summary:`${camp.name}: ${camp.openRate?.toFixed(1)}% open, ${camp.clickRate?.toFixed(1)}% click rate.`,trends:["Monitor engagement","Review bounces","Track list health"],recommendations:["A/B test subjects","Segment audience","Optimize timing"]};const nn={...notes,[camp.id]:fb};setNotes(nn);persist(campaigns,clickers,emailVisuals,nn)}setGenerating(false)};
  const removeNote=id=>{const nn={...notes};delete nn[id];setNotes(nn);persist(campaigns,clickers,emailVisuals,nn)};
  const clearAll=async()=>{if(confirm("Clear all data?")){setCampaigns([]);setClickers([]);setEmailVisuals([]);setNotes({});await clearAllData()}};

  // Exclude Pub Comms from chart/click data
  const nonPubCampaigns=useMemo(()=>campaigns.filter(c=>c.type!=="Pub Comms"),[campaigns]);
  const nonPubClickers=useMemo(()=>{const pn=new Set(campaigns.filter(c=>c.type==="Pub Comms").map(c=>c.name));return clickers.filter(c=>!pn.has(c.campaignName))},[clickers,campaigns]);

  const tabs=[{l:"Overview",i:BarChart3},{l:"Campaign List",i:FileText},{l:"Clicks",i:MousePointerClick},{l:"Visuals",i:Image},{l:"AI Notes",i:Brain},{l:"Custom Analysis",i:GitMerge},{l:"Custom Reports",i:FileText}];

  if(loading)return <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:C.bg2,fontFamily:"'DM Sans',sans-serif"}}><div style={{width:40,height:40,border:`3px solid ${C.bg3}`,borderTopColor:C.primary,borderRadius:"50%",animation:"spin .8s linear infinite"}}/><style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style></div>;

  return(
    <div style={{minHeight:"100vh",background:C.bg2,fontFamily:"'DM Sans',sans-serif"}}>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}@keyframes fadeIn{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}@keyframes slideUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}*{box-sizing:border-box;margin:0;padding:0}input,select,textarea,button{font-family:'DM Sans',sans-serif}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:${C.bg3};border-radius:3px}`}</style>
      <header style={{background:`linear-gradient(135deg, ${C.dark} 0%, ${C.secondary} 100%)`,padding:"22px 28px 20px"}}><div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}><div style={{display:"flex",alignItems:"center",gap:14}}><div style={{width:42,height:42,borderRadius:12,background:C.primary,display:"flex",alignItems:"center",justifyContent:"center"}}><Mail size={20} color="#fff"/></div><div><h1 style={{fontSize:20,fontWeight:700,color:"#fff",lineHeight:1.2}}>Email Campaign Analytics</h1><p style={{fontSize:10,color:"rgba(255,255,255,0.35)",marginTop:2}}>by kenn.d</p></div></div><div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:6}}><div style={{display:"flex",gap:8}}><button onClick={()=>setShowSettings(true)} style={{display:"flex",alignItems:"center",gap:4,padding:"8px 14px",background:"rgba(255,255,255,0.1)",color:"rgba(255,255,255,0.7)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:9,fontSize:11,cursor:"pointer"}}><Settings size={13}/> AI Settings</button><button onClick={()=>setShowUpload(true)} style={{display:"flex",alignItems:"center",gap:5,padding:"8px 18px",background:C.primary,color:"#fff",border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:"pointer"}}><Upload size={13}/> Upload</button><button onClick={clearAll} style={{padding:"8px 10px",background:"rgba(255,255,255,0.1)",color:"rgba(255,255,255,0.5)",border:"1px solid rgba(255,255,255,0.12)",borderRadius:9,cursor:"pointer"}}><Trash2 size={13}/></button></div><p style={{fontSize:10,color:"rgba(255,255,255,0.3)"}}>{campaigns.length} campaigns | {clickers.length} contacts</p></div></div></header>
      <nav style={{display:"flex",padding:"0 24px",background:C.white,borderBottom:"1px solid #eae6ef",overflowX:"auto"}}>{tabs.map((t,i)=><button key={i} onClick={()=>setTab(i)} style={{display:"flex",alignItems:"center",gap:5,padding:"11px 14px",background:"none",border:"none",borderBottom:tab===i?`2px solid ${C.primary}`:"2px solid transparent",color:tab===i?C.primary:C.muted,fontSize:11,fontWeight:tab===i?700:500,cursor:"pointer",whiteSpace:"nowrap"}}><t.i size={13}/> {t.l}</button>)}</nav>
      <main style={{padding:"20px 24px",maxWidth:1400,margin:"0 auto"}}>
        {tab===0&&<OverviewTab campaigns={campaigns} nonPub={nonPubCampaigns} removeCampaign={removeCampaign}/>}
        {tab===1&&<CampaignListTab campaigns={campaigns} removeCampaign={removeCampaign}/>}
        {tab===2&&<ClicksTab campaigns={nonPubCampaigns} clickers={nonPubClickers}/>}
        {tab===3&&<VisualsTab campaigns={nonPubCampaigns} emailVisuals={emailVisuals} setEmailVisuals={ev=>{setEmailVisuals(ev);persist(campaigns,clickers,ev,notes)}}/>}
        {tab===4&&<NotesTab campaigns={nonPubCampaigns} notes={notes} generateNotes={generateNotes} generating={generating} removeNote={removeNote}/>}
        {tab===5&&<CustomAnalysisTab campaigns={nonPubCampaigns} clickers={nonPubClickers}/>}
        {tab===6&&<CustomReportsTab aiConfig={aiConfig}/>}
      </main>
      {showUpload&&<UploadModal onClose={()=>setShowUpload(false)} addCampaign={addCampaign} addClickers={addClickers}/>}
      {showSettings&&<SettingsModal config={aiConfig} onSave={c=>{setAiConfig(c);persist(campaigns,clickers,emailVisuals,notes,c);setShowSettings(false)}} onClose={()=>setShowSettings(false)}/>}
      <footer style={{textAlign:"center",padding:"20px 24px 16px",borderTop:"1px solid #e0dce6",marginTop:24}}><p style={{fontSize:10,color:C.muted}}>Email Campaign Analytics by kenn.d</p></footer>
    </div>
  );
}

// ========= SETTINGS MODAL =========
function SettingsModal({config,onSave,onClose}){const[cfg,setCfg]=useState({...config});const u=(k,v)=>setCfg(p=>({...p,[k]:v}));return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,backdropFilter:"blur(4px)"}} onClick={onClose}><div onClick={e=>e.stopPropagation()} style={{background:C.white,borderRadius:18,width:"92%",maxWidth:480,animation:"slideUp .3s ease"}}><div style={{padding:"18px 22px",borderBottom:"1px solid #f0ecf4",display:"flex",justifyContent:"space-between",alignItems:"center"}}><h2 style={{fontSize:16,fontWeight:700,color:C.dark}}>AI Settings</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={17}/></button></div><div style={{padding:22}}><div style={{marginBottom:18}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>AI Provider</label><div style={{display:"flex",gap:8}}>{[{v:"anthropic",l:"Anthropic (Claude)"},{v:"ollama",l:"Ollama (Local)"}].map(o=><button key={o.v} onClick={()=>u("provider",o.v)} style={{flex:1,padding:"10px",borderRadius:9,border:"1px solid",fontSize:12,fontWeight:600,cursor:"pointer",background:cfg.provider===o.v?C.secondary:"transparent",color:cfg.provider===o.v?"#fff":C.dark,borderColor:cfg.provider===o.v?C.secondary:"#ddd"}}>{o.l}</button>)}</div></div>{cfg.provider==="anthropic"&&<div style={{marginBottom:18}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>API Key (optional)</label><input type="password" value={cfg.apiKey} onChange={e=>u("apiKey",e.target.value)} placeholder="sk-ant-..." style={{width:"100%",padding:"10px 12px",borderRadius:9,border:"1px solid #e8e4ee",fontSize:12,outline:"none"}}/><p style={{fontSize:10,color:C.muted,marginTop:4}}>Leave blank when using inside Claude.ai artifacts.</p></div>}{cfg.provider==="ollama"&&<><div style={{marginBottom:14}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>Ollama URL</label><input value={cfg.ollamaUrl} onChange={e=>u("ollamaUrl",e.target.value)} style={{width:"100%",padding:"10px 12px",borderRadius:9,border:"1px solid #e8e4ee",fontSize:12,outline:"none"}}/></div><div style={{marginBottom:18}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>Model</label><input value={cfg.ollamaModel} onChange={e=>u("ollamaModel",e.target.value)} style={{width:"100%",padding:"10px 12px",borderRadius:9,border:"1px solid #e8e4ee",fontSize:12,outline:"none"}}/></div></>}<div style={{display:"flex",gap:8}}><button onClick={onClose} style={{flex:1,padding:"11px",background:"#f5f2f8",color:C.dark,border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:"pointer"}}>Cancel</button><button onClick={()=>onSave(cfg)} style={{flex:2,padding:"11px",background:C.primary,color:"#fff",border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:"pointer"}}>Save</button></div></div></div></div>}

// ========= TAB: OVERVIEW =========
function OverviewTab({campaigns,nonPub,removeCampaign}){const[tf,setTf]=useState("");const[lf,setLf]=useState("");
const filteredByType = useMemo(() => tf ? nonPub.filter(c => c.type === tf) : nonPub, [nonPub, tf]);
const allL=useMemo(()=>[...new Set(filteredByType.map(c=>c.listName).filter(Boolean))],[filteredByType]);
const filtered=useMemo(()=>{let c=[...nonPub];if(tf)c=c.filter(x=>x.type===tf);if(lf)c=c.filter(x=>x.listName===lf);return c},[nonPub,tf,lf]);const pubComms=campaigns.filter(c=>c.type==="Pub Comms");
if(campaigns.length===0)return <Empty msg="Upload your first campaign report to get started."/>;
const tot={sends:0,opens:0,clicks:0,bounces:0,unsubs:0};filtered.forEach(c=>{tot.sends+=c.sends||0;tot.opens+=c.opens||0;tot.clicks+=c.clicks||0;tot.bounces+=c.bounces||0;tot.unsubs+=c.unsubs||0});
const td=useMemo(()=>{return [...filtered].sort((a,b)=>{const da=parseDate(a.date);const db=parseDate(b.date);if(!da&&!db)return 0;if(!da)return -1;if(!db)return 1;return da-db}).map(c=>{const d=parseDate(c.date);const monthLabel=d?d.toLocaleDateString('en-US',{month:'short',year:'2-digit'}):'N/A';return {month:monthLabel,campaign:c.name,openRate:c.openRate||0,clickRate:c.clickRate||0}})},[filtered]);const top5=[...filtered].sort((a,b)=>(b.openRate||0)-(a.openRate||0)).slice(0,5);const topSub=[...filtered].filter(c=>c.subjectLine).sort((a,b)=>(b.openRate||0)-(a.openRate||0)).slice(0,5);const byType={};filtered.forEach(c=>{if(!byType[c.type])byType[c.type]=[];byType[c.type].push(c)});
const expCSV=()=>{downloadCSVData(["Campaign","Type","List","Sends","Opens","Open Rate","Clicks","Click Rate","Bounces","Unsubs","Subject","Date"],filtered.map(c=>[c.name,c.type,c.listName,c.sends,c.opens,(c.openRate||0).toFixed(1)+"%",c.clicks,(c.clickRate||0).toFixed(1)+"%",c.bounces,c.unsubs,c.subjectLine,c.date]),"overview")};
return <div id="overview-page" style={{animation:"fadeIn .3s ease"}}>
<div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap",alignItems:"center",justifyContent:"space-between"}}><div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}><span style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase"}}>Filter:</span><Sel value={tf} onChange={v=>{setTf(v);setLf("")}} options={CAMPAIGN_TYPES.filter(t=>t!=="Pub Comms")} placeholder="All Types"/><Sel value={lf} onChange={setLf} options={allL} placeholder="All Lists"/>{(tf||lf)&&<button onClick={()=>{setTf("");setLf("")}} style={{fontSize:11,color:C.primary,background:"none",border:"none",cursor:"pointer",fontWeight:600}}>Clear</button>}</div><div style={{display:"flex",gap:6}}><DlBtn id="overview-page" name="overview"/><button onClick={expCSV} style={{display:"flex",alignItems:"center",gap:3,padding:"4px 8px",background:"#f5f2f8",border:"1px solid #e8e4ee",borderRadius:6,fontSize:10,cursor:"pointer",color:C.muted,fontWeight:600}}><Download size={11}/> CSV</button></div></div>
<div id="kpi-cards" style={{display:"grid",gridTemplateColumns:"repeat(auto-fit, minmax(180px, 1fr))",gap:12,marginBottom:20}}><KPI label="Open Rate" value={`${tot.sends>0?(tot.opens/tot.sends*100).toFixed(1):"0"}%`} sub={`${tot.opens.toLocaleString()} opens`} icon={Mail} color={C.primary}/><KPI label="Click Rate" value={`${tot.sends>0?(tot.clicks/tot.sends*100).toFixed(1):"0"}%`} sub={`${tot.clicks.toLocaleString()} clicks`} icon={MousePointerClick} color={C.secondary}/><KPI label="Bounce Rate" value={`${tot.sends>0?(tot.bounces/tot.sends*100).toFixed(1):"0"}%`} sub={`${tot.bounces.toLocaleString()} bounces`} icon={AlertTriangle} color={C.warning}/><KPI label="Unsubscribes" value={tot.unsubs.toLocaleString()} sub={`${filtered.length} campaigns`} icon={Users} color={C.danger}/></div>
<div style={{display:"flex",justifyContent:"flex-end",marginBottom:6,marginTop:-12}}><DlBtn id="kpi-cards" name="kpi_summary"/></div>
<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:20}}><CC title="Open Rate Trend" id="chart-open"><ResponsiveContainer width="100%" height={190}><AreaChart data={td}><defs><linearGradient id="og" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor={C.primary} stopOpacity={.15}/><stop offset="95%" stopColor={C.primary} stopOpacity={0}/></linearGradient></defs><CartesianGrid strokeDasharray="3 3" stroke="#f0ecf4"/><XAxis dataKey="month" fontSize={9} tick={{fill:C.muted}}/><YAxis fontSize={9} tick={{fill:C.muted}} tickFormatter={v=>`${v}%`}/><Tooltip content={({active,payload})=>{if(!active||!payload?.[0])return null;const d=payload[0].payload;return <div style={{background:"#fff",border:"1px solid #eee",borderRadius:8,padding:"8px 12px",fontSize:11}}><div style={{fontWeight:700,color:C.dark,marginBottom:2}}>{d.campaign}</div><div style={{color:C.primary}}>Open Rate: {d.openRate.toFixed(1)}%</div><div style={{color:C.muted,fontSize:10}}>{d.month}</div></div>}}/><Area type="monotone" dataKey="openRate" stroke={C.primary} fill="url(#og)" strokeWidth={2} dot={{r:3,fill:C.primary}}/></AreaChart></ResponsiveContainer></CC><CC title="Click Rate Trend" id="chart-click"><ResponsiveContainer width="100%" height={190}><AreaChart data={td}><defs><linearGradient id="cg" x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor={C.secondary} stopOpacity={.15}/><stop offset="95%" stopColor={C.secondary} stopOpacity={0}/></linearGradient></defs><CartesianGrid strokeDasharray="3 3" stroke="#f0ecf4"/><XAxis dataKey="month" fontSize={9} tick={{fill:C.muted}}/><YAxis fontSize={9} tick={{fill:C.muted}} tickFormatter={v=>`${v}%`}/><Tooltip content={({active,payload})=>{if(!active||!payload?.[0])return null;const d=payload[0].payload;return <div style={{background:"#fff",border:"1px solid #eee",borderRadius:8,padding:"8px 12px",fontSize:11}}><div style={{fontWeight:700,color:C.dark,marginBottom:2}}>{d.campaign}</div><div style={{color:C.secondary}}>Click Rate: {d.clickRate.toFixed(1)}%</div><div style={{color:C.muted,fontSize:10}}>{d.month}</div></div>}}/><Area type="monotone" dataKey="clickRate" stroke={C.secondary} fill="url(#cg)" strokeWidth={2} dot={{r:3,fill:C.secondary}}/></AreaChart></ResponsiveContainer></CC></div>
<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:20}}><CC title="Top 5 Campaigns" id="top-camps">{top5.map((c,i)=><div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:i<4?"1px solid #f5f2f8":"none"}}><div style={{flex:1,minWidth:0}}><div style={{fontSize:12,fontWeight:600,color:C.dark,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{i+1}. {c.name}</div><div style={{fontSize:10,color:C.muted}}>{c.listName}</div></div><div style={{display:"flex",gap:10,fontSize:10,flexShrink:0}}><span style={{color:C.primary,fontWeight:600}}>{c.opens?.toLocaleString()} ({c.openRate?.toFixed(1)}%)</span><span style={{color:C.secondary,fontWeight:600}}>{c.clicks?.toLocaleString()} ({c.clickRate?.toFixed(1)}%)</span></div></div>)}</CC><CC title="Best Subject Lines" id="best-sub">{topSub.length===0?<p style={{fontSize:11,color:C.muted}}>No subject lines yet.</p>:topSub.map((c,i)=><div key={i} style={{padding:"8px 0",borderBottom:i<topSub.length-1?"1px solid #f5f2f8":"none"}}><div style={{fontSize:12,fontWeight:600,color:C.dark,marginBottom:2}}>{c.subjectLine}</div><div style={{display:"flex",gap:8,fontSize:10,color:C.muted,alignItems:"center"}}><span>{c.name}</span><Badge color={C.success}>{c.openRate?.toFixed(1)}% open</Badge></div></div>)}</CC></div>
<h3 style={{fontSize:13,fontWeight:700,color:C.dark,marginBottom:12}}>Campaigns by Type</h3>
<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit, minmax(260px, 1fr))",gap:12}}>
{CAMPAIGN_TYPES.map(type=>{const camps=type==="Pub Comms"?pubComms:(byType[type]||[]);return <div key={type} style={{background:C.white,borderRadius:14,padding:16,border:"1px solid #f0ecf4"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><span style={{fontSize:12,fontWeight:700,color:C.dark}}>{type}</span><Badge color={C.secondary}>{camps.length}</Badge></div>{camps.length===0?<p style={{fontSize:11,color:C.muted}}>None</p>:camps.map((c,i)=><div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 0",borderTop:i>0?"1px solid #f8f6fa":"none"}}><div style={{flex:1,minWidth:0}}><div style={{fontSize:11,fontWeight:600,color:C.dark}}>{c.name}</div><div style={{fontSize:10,color:C.muted}}>{type==="Pub Comms"?`Sent: ${c.date||"N/A"}`:`List: ${c.listName} | Open: ${c.openRate?.toFixed(1)}% | Click: ${c.clickRate?.toFixed(1)}%`}</div></div>{type!=="Pub Comms"&&<button onClick={()=>{if(confirm(`Remove "${c.name}"?`))removeCampaign(c.id)}} style={{background:"none",border:"none",cursor:"pointer",color:C.muted,padding:3}}><Trash2 size={12}/></button>}</div>)}</div>})}
</div></div>}

// ========= TAB: CAMPAIGN LIST =========
function CampaignListTab({campaigns,removeCampaign}){
  const[tf,setTf]=useState("");const[lf,setLf]=useState("");const[dateFrom,setDateFrom]=useState("");const[dateTo,setDateTo]=useState("");const[search,setSearch]=useState("");
  const[sortCol,setSortCol]=useState("date");const[sortDir,setSortDir]=useState("desc");
  const filteredByType = useMemo(() => tf ? campaigns.filter(x => x.type === tf) : campaigns, [campaigns, tf]);
  const allL = useMemo(() => [...new Set(filteredByType.map(c => c.listName).filter(Boolean))], [filteredByType]);
  const toggleSort = (col) => { if (sortCol === col) setSortDir(d => d === "asc" ? "desc" : "asc"); else { setSortCol(col); setSortDir(col === "name" ? "asc" : "desc"); } };
  const sortIcon = (col) => sortCol === col ? (sortDir === "asc" ? " \u25B2" : " \u25BC") : "";
  const sorted=useMemo(()=>{let c=[...campaigns];if(tf)c=c.filter(x=>x.type===tf);if(lf)c=c.filter(x=>x.listName===lf);if(search){const s=search.toLowerCase();c=c.filter(x=>(x.name||"").toLowerCase().includes(s)||(x.listName||"").toLowerCase().includes(s))}if(dateFrom||dateTo){c=c.filter(x=>{const d=parseDate(x.date);if(!d)return false;if(dateFrom&&d<new Date(dateFrom))return false;if(dateTo&&d>new Date(dateTo+"T23:59:59"))return false;return true})}
  return c.sort((a,b)=>{let va,vb;if(sortCol==="date"){va=parseDate(a.date);vb=parseDate(b.date);if(!va&&!vb)return 0;if(!va)return 1;if(!vb)return -1;return sortDir==="asc"?va-vb:vb-va}if(sortCol==="name"||sortCol==="type"||sortCol==="listName"){va=(a[sortCol]||"").toLowerCase();vb=(b[sortCol]||"").toLowerCase();return sortDir==="asc"?va.localeCompare(vb):vb.localeCompare(va)}va=a[sortCol]||0;vb=b[sortCol]||0;return sortDir==="asc"?va-vb:vb-va})},[campaigns,tf,lf,dateFrom,dateTo,search,sortCol,sortDir]);
  const expCSV=()=>{downloadCSVData(["Campaign","Type","List","Date","Sends","Opens","Open Rate","Clicks","Click Rate","Bounces","Unsubs","Subject"],sorted.map(c=>[c.name,c.type,c.listName,c.date,c.sends,c.opens,(c.openRate||0).toFixed(1)+"%",c.clicks,(c.clickRate||0).toFixed(1)+"%",c.bounces,c.unsubs,c.subjectLine]),"campaign_list")};
  const cols=[{key:"name",label:"Campaign"},{key:"type",label:"Type"},{key:"listName",label:"List"},{key:"date",label:"Date Sent"},{key:"sends",label:"Sends"},{key:"opens",label:"Opens"},{key:"openRate",label:"Open %"},{key:"clicks",label:"Clicks"},{key:"clickRate",label:"Click %"},{key:"bounces",label:"Bounces"},{key:"unsubs",label:"Unsubs"}];
  return <div style={{animation:"fadeIn .3s ease"}}>
  <div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap",alignItems:"center"}}><span style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase"}}>Filter:</span><Sel value={tf} onChange={v=>{setTf(v);setLf("")}} options={CAMPAIGN_TYPES} placeholder="All Types"/><Sel value={lf} onChange={setLf} options={allL} placeholder="All Lists"/><div style={{display:"flex",gap:4,alignItems:"center"}}><span style={{fontSize:10,color:C.muted}}>From:</span><input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)} style={{padding:"6px 8px",borderRadius:6,border:"1px solid #e8e4ee",fontSize:11,outline:"none"}}/><span style={{fontSize:10,color:C.muted}}>To:</span><input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)} style={{padding:"6px 8px",borderRadius:6,border:"1px solid #e8e4ee",fontSize:11,outline:"none"}}/></div>{(tf||lf||dateFrom||dateTo)&&<button onClick={()=>{setTf("");setLf("");setDateFrom("");setDateTo("")}} style={{fontSize:11,color:C.primary,background:"none",border:"none",cursor:"pointer",fontWeight:600}}>Clear</button>}</div>
  <div style={{background:C.white,borderRadius:14,padding:18,border:"1px solid #f0ecf4"}}>
  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><h3 style={{fontSize:13,fontWeight:700,color:C.dark}}>All Campaigns ({sorted.length})</h3><div style={{display:"flex",gap:8}}><div style={{position:"relative"}}><Search size={12} style={{position:"absolute",left:8,top:8,color:C.muted}}/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search..." style={{padding:"7px 8px 7px 26px",borderRadius:8,border:"1px solid #e8e4ee",fontSize:11,width:160,outline:"none"}}/></div><button onClick={expCSV} style={{display:"flex",alignItems:"center",gap:4,padding:"7px 12px",background:C.secondary,color:"#fff",border:"none",borderRadius:8,fontSize:11,fontWeight:600,cursor:"pointer"}}><Download size={11}/> CSV</button></div></div>
  <div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}><thead><tr style={{borderBottom:"2px solid #f0ecf4"}}>{cols.map(h=><th key={h.key} onClick={()=>toggleSort(h.key)} style={{textAlign:"left",padding:"7px 8px",color:sortCol===h.key?C.secondary:C.muted,fontWeight:600,fontSize:10,textTransform:"uppercase",cursor:"pointer",whiteSpace:"nowrap",userSelect:"none"}}>{h.label}{sortIcon(h.key)}</th>)}<th style={{padding:"7px 8px"}}></th></tr></thead><tbody>{sorted.map((c,i)=><tr key={i} style={{borderBottom:"1px solid #f8f6fa"}} onMouseEnter={e=>e.currentTarget.style.background="#faf8fc"} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><td style={{padding:"7px 8px",fontWeight:600,color:C.dark,maxWidth:200,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.name}</td><td style={{padding:"7px 8px"}}><Badge color={c.type==="Pub Comms"?C.muted:C.secondary}>{c.type}</Badge></td><td style={{padding:"7px 8px",fontSize:10}}>{c.listName}</td><td style={{padding:"7px 8px",fontSize:10,color:C.muted,whiteSpace:"nowrap"}}>{c.date}</td><td style={{padding:"7px 8px"}}>{c.sends?.toLocaleString()}</td><td style={{padding:"7px 8px"}}>{c.opens?.toLocaleString()}</td><td style={{padding:"7px 8px",color:C.primary,fontWeight:600}}>{c.openRate?.toFixed(1)}%</td><td style={{padding:"7px 8px"}}>{c.clicks?.toLocaleString()}</td><td style={{padding:"7px 8px",color:C.secondary,fontWeight:600}}>{c.clickRate?.toFixed(1)}%</td><td style={{padding:"7px 8px"}}>{c.bounces}</td><td style={{padding:"7px 8px"}}>{c.unsubs}</td><td style={{padding:"7px 8px"}}><button onClick={()=>{if(confirm(`Remove "${c.name}"?`))removeCampaign(c.id)}} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><Trash2 size={12}/></button></td></tr>)}</tbody></table></div></div></div>}

// ========= TAB: CLICKS =========
function ClicksTab({campaigns,clickers}){
  const[tf,setTf]=useState("");const[lf,setLf]=useState("");const[search,setSearch]=useState("");const[cf,setCf]=useState("company");const[pf,setPf]=useState("state");
  if(clickers.length===0)return <Empty msg="Upload clicker data to see engagement analysis."/>;
  // Cascading filter: lists shown depend on selected type
  const filteredCampaignsByType = useMemo(() => tf ? campaigns.filter(c => c.type === tf) : campaigns, [campaigns, tf]);
  const allL = useMemo(() => [...new Set(filteredCampaignsByType.map(c => c.listName).filter(Boolean))], [filteredCampaignsByType]);
  const filtered=useMemo(()=>{let list=[...clickers];if(tf){const cn=campaigns.filter(c=>c.type===tf).map(c=>c.name);list=list.filter(c=>cn.includes(c.campaignName))}if(lf)list=list.filter(c=>c.listName===lf);if(search){const s=search.toLowerCase();list=list.filter(c=>Object.values(c).some(v=>String(v).toLowerCase().includes(s)))}return list},[clickers,tf,lf,search,campaigns]);
  const getTop=(field,n=8)=>{const m={};filtered.forEach(c=>{const v=c[field];if(v)m[v]=(m[v]||0)+1});return Object.entries(m).sort((a,b)=>b[1]-a[1]).slice(0,n)};
  const barData=useMemo(()=>getTop(cf),[filtered,cf]);
  const pieData=useMemo(()=>getTop(pf),[filtered,pf]);

  const expCSV=()=>{downloadCSVData(["Email","First Name","Last Name","Company","Account","State","Career Level","Dept","Contact Type","Region","Campaign","List"],filtered.map(c=>[c.email,c.firstName,c.lastName,c.company,c.accountName,c.state,c.careerLevel,c.department,c.contactType,c.region,c.campaignName,c.listName]),"clickers")};
  return <div style={{animation:"fadeIn .3s ease"}}>
  <div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap",alignItems:"center"}}><span style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase"}}>Filter:</span><Sel value={tf} onChange={v=>{setTf(v);setLf("")}} options={CAMPAIGN_TYPES.filter(t=>t!=="Pub Comms")} placeholder="All Types"/><Sel value={lf} onChange={setLf} options={allL} placeholder="All Lists"/>{(tf||lf)&&<button onClick={()=>{setTf("");setLf("")}} style={{fontSize:11,color:C.primary,background:"none",border:"none",cursor:"pointer",fontWeight:600}}>Clear</button>}</div>
  <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit, minmax(160px, 1fr))",gap:12,marginBottom:20}}><KPI label="Total Clickers" value={filtered.length.toLocaleString()} icon={Users} color={C.primary}/><KPI label="Companies" value={new Set(filtered.map(c=>c.company).filter(Boolean)).size.toLocaleString()} icon={BarChart3} color={C.secondary}/><KPI label="States" value={new Set(filtered.map(c=>c.state).filter(Boolean)).size.toLocaleString()} icon={TrendingUp} color="#7c3aed"/><KPI label="Campaigns" value={new Set(filtered.map(c=>c.campaignName)).size.toLocaleString()} icon={Mail} color={C.bg1}/></div>
  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:20}}><CC title="Top by Contact Field (List Column)" id="chart-top" actions={<Sel value={cf} onChange={setCf} options={CF.map(f=>({value:f.key,label:f.label}))}/>}><ResponsiveContainer width="100%" height={300}><BarChart data={barData.map(([n,c])=>({name:n.slice(0,24),count:c}))} layout="vertical"><CartesianGrid strokeDasharray="3 3" stroke="#f0ecf4"/><XAxis type="number" fontSize={10} tick={{fill:C.muted}}/><YAxis dataKey="name" type="category" fontSize={9} tick={{fill:C.muted}} width={140}/><Tooltip contentStyle={{borderRadius:8,border:"1px solid #eee",fontSize:11}}/><Bar dataKey="count" fill={C.primary} radius={[0,5,5,0]}/></BarChart></ResponsiveContainer></CC><CC title="Distribution" id="chart-dist" actions={<Sel value={pf} onChange={setPf} options={CF.map(f=>({value:f.key,label:f.label}))}/>}><ResponsiveContainer width="100%" height={300}><PieChart><Pie data={pieData.map(([n,v])=>({name:n,value:v}))} cx="50%" cy="45%" outerRadius={90} innerRadius={40} dataKey="value" paddingAngle={3}>{pieData.map((_,i)=><Cell key={i} fill={PIE_C[i%PIE_C.length]}/>)}</Pie><Tooltip contentStyle={{borderRadius:8,border:"1px solid #eee",fontSize:11}}/><Legend iconSize={8} wrapperStyle={{fontSize:9,lineHeight:"18px",paddingTop:12}}/></PieChart></ResponsiveContainer></CC></div>

  {/* Clicker Database */}
  <div style={{background:C.white,borderRadius:14,padding:18,border:"1px solid #f0ecf4"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12,flexWrap:"wrap",gap:8}}><h3 style={{fontSize:13,fontWeight:700,color:C.dark}}>Clicker Database</h3><div style={{display:"flex",gap:8}}><div style={{position:"relative"}}><Search size={12} style={{position:"absolute",left:8,top:8,color:C.muted}}/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search..." style={{padding:"7px 8px 7px 26px",borderRadius:8,border:"1px solid #e8e4ee",fontSize:11,width:160,outline:"none"}}/></div><button onClick={expCSV} style={{display:"flex",alignItems:"center",gap:4,padding:"7px 12px",background:C.secondary,color:"#fff",border:"none",borderRadius:8,fontSize:11,fontWeight:600,cursor:"pointer"}}><Download size={11}/> Export</button></div></div><div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}><thead><tr style={{borderBottom:"2px solid #f0ecf4"}}>{["Email","Name","Company","Account","State","Level","Dept","Type","Campaign","List"].map(h=><th key={h} style={{textAlign:"left",padding:"7px 8px",color:C.muted,fontWeight:600,fontSize:10,textTransform:"uppercase"}}>{h}</th>)}</tr></thead><tbody>{filtered.slice(0,50).map((c,i)=><tr key={i} style={{borderBottom:"1px solid #f8f6fa"}} onMouseEnter={e=>e.currentTarget.style.background="#faf8fc"} onMouseLeave={e=>e.currentTarget.style.background="transparent"}><td style={{padding:"7px 8px",color:C.secondary,fontWeight:500,fontSize:11}}>{c.email}</td><td style={{padding:"7px 8px"}}>{c.firstName} {c.lastName}</td><td style={{padding:"7px 8px"}}>{c.company}</td><td style={{padding:"7px 8px"}}>{c.accountName}</td><td style={{padding:"7px 8px"}}>{c.state}</td><td style={{padding:"7px 8px"}}>{c.careerLevel}</td><td style={{padding:"7px 8px"}}>{c.department}</td><td style={{padding:"7px 8px"}}>{c.contactType}</td><td style={{padding:"6px 6px"}}><span style={{fontSize:9,color:C.secondary,fontWeight:600,background:C.secondary+"12",padding:"2px 7px",borderRadius:12,whiteSpace:"nowrap"}}>{(c.campaignName||"").slice(0,20)}</span></td><td style={{padding:"7px 8px",fontSize:10,color:C.muted}}>{c.listName}</td></tr>)}</tbody></table>{filtered.length>50&&<p style={{textAlign:"center",padding:8,color:C.muted,fontSize:10}}>Showing 50 of {filtered.length}</p>}</div></div></div>}

// ========= TAB: VISUALS =========
function VisualsTab({campaigns,emailVisuals,setEmailVisuals}){const[sc,setSc]=useState("");const[pu,setPu]=useState("");const addUrl=()=>{if(!sc||!pu)return;setEmailVisuals([...emailVisuals,{campaignName:sc,type:"url",value:pu,id:Date.now().toString()}]);setPu("")};const hImg=(file,cn)=>{const r=new FileReader();r.onload=e=>{setEmailVisuals([...emailVisuals,{campaignName:cn,type:"image",value:e.target.result,id:Date.now().toString(),fileName:file.name}])};r.readAsDataURL(file)};const rm=id=>setEmailVisuals(emailVisuals.filter(x=>x.id!==id));return <div style={{animation:"fadeIn .3s ease"}}><div style={{background:C.white,borderRadius:14,padding:18,border:"1px solid #f0ecf4",marginBottom:20}}><h3 style={{fontSize:13,fontWeight:700,color:C.dark,marginBottom:12}}>Add Email Preview</h3><div style={{display:"flex",gap:8,alignItems:"flex-end",flexWrap:"wrap"}}><div><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:3,textTransform:"uppercase"}}>Campaign</label><select value={sc} onChange={e=>setSc(e.target.value)} style={{padding:"8px 10px",borderRadius:8,border:"1px solid #e8e4ee",fontSize:11,minWidth:170,outline:"none"}}><option value="">Select...</option>{campaigns.map((c,i)=><option key={i} value={c.name}>{c.name} ({c.listName})</option>)}</select></div><div style={{flex:1,minWidth:160}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:3,textTransform:"uppercase"}}>Preview URL</label><input value={pu} onChange={e=>setPu(e.target.value)} placeholder="https://mailchi.mp/..." style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #e8e4ee",fontSize:11,outline:"none"}}/></div><button onClick={addUrl} style={{padding:"8px 14px",background:C.primary,color:"#fff",border:"none",borderRadius:8,fontSize:11,fontWeight:600,cursor:"pointer"}}>Add URL</button></div></div>{campaigns.map((camp,ci)=><VCard key={ci} camp={camp} vis={emailVisuals.filter(v=>v.campaignName===camp.name)} hImg={hImg} rm={rm}/>)}</div>}
function VCard({camp,vis,hImg,rm}){const ref=useRef(null);return <div style={{background:C.white,borderRadius:14,padding:16,border:"1px solid #f0ecf4",marginBottom:12}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}><div><span style={{fontSize:12,fontWeight:700,color:C.dark}}>{camp.name}</span> <Badge color={C.secondary}>{camp.listName}</Badge></div><div style={{display:"flex",gap:6,alignItems:"center"}}><span style={{fontSize:10,color:C.muted}}>{vis.length} items</span><input ref={ref} type="file" accept="image/*" style={{display:"none"}} onChange={e=>e.target.files[0]&&hImg(e.target.files[0],camp.name)}/><button onClick={()=>ref.current?.click()} style={{display:"flex",alignItems:"center",gap:3,padding:"5px 10px",background:C.bg3,border:"none",borderRadius:6,fontSize:10,fontWeight:600,cursor:"pointer",color:C.dark}}><Image size={11}/> Upload Screenshot</button></div></div>{vis.length===0?<p style={{fontSize:11,color:C.muted,padding:"8px 0"}}>No previews.</p>:<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(220px, 1fr))",gap:8}}>{vis.map(v=><div key={v.id} style={{border:"1px solid #eee",borderRadius:8,padding:10,position:"relative"}}>{v.type==="image"?<div><img src={v.value} alt={v.fileName} style={{width:"100%",borderRadius:5,marginBottom:4}}/><p style={{fontSize:10,color:C.muted}}>{v.fileName}</p></div>:<a href={v.value} target="_blank" rel="noopener" style={{display:"flex",alignItems:"center",gap:5,color:C.secondary,fontSize:11,fontWeight:500,textDecoration:"none"}}><ExternalLink size={12}/> View Preview</a>}<button onClick={()=>rm(v.id)} style={{position:"absolute",top:5,right:5,background:"#fff",border:"1px solid #eee",borderRadius:4,cursor:"pointer",color:C.muted,padding:2}}><X size={11}/></button></div>)}</div>}</div>}

// ========= TAB: AI NOTES =========
function NotesTab({campaigns,notes,generateNotes,generating,removeNote}){const[tf,setTf]=useState("");const[lf,setLf]=useState("");const allL=[...new Set(campaigns.map(c=>c.listName).filter(Boolean))];const filtered=useMemo(()=>{let c=[...campaigns];if(tf)c=c.filter(x=>x.type===tf);if(lf)c=c.filter(x=>x.listName===lf);return c},[campaigns,tf,lf]);if(campaigns.length===0)return <Empty msg="Upload campaign data to generate AI insights."/>;return <div style={{animation:"fadeIn .3s ease"}}><div style={{background:"#fef7f0",borderRadius:10,padding:14,marginBottom:18,border:"1px solid #fde8d0"}}><p style={{fontSize:12,color:"#92400e",lineHeight:1.6}}><strong>How AI Notes work:</strong> Go to <strong>AI Settings</strong> in the header to switch between Anthropic (Claude) and Ollama (local/offline). Notes persist across sessions.</p></div><div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap",alignItems:"center"}}><span style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase"}}>Filter:</span><Sel value={tf} onChange={setTf} options={CAMPAIGN_TYPES.filter(t=>t!=="Pub Comms")} placeholder="All Types"/><Sel value={lf} onChange={setLf} options={allL} placeholder="All Lists"/>{(tf||lf)&&<button onClick={()=>{setTf("");setLf("")}} style={{fontSize:11,color:C.primary,background:"none",border:"none",cursor:"pointer",fontWeight:600}}>Clear</button>}</div><div style={{display:"grid",gap:14}}>{filtered.map((camp,i)=>{const note=notes[camp.id];const nid=`note-${camp.id}`;return <div key={i} id={nid} style={{background:C.white,borderRadius:14,padding:20,border:"1px solid #f0ecf4"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}><div><h3 style={{fontSize:14,fontWeight:700,color:C.dark,marginBottom:4}}>{camp.name}</h3><div style={{display:"flex",gap:5,flexWrap:"wrap"}}><Badge color={C.secondary}>{camp.type}</Badge><Badge color="#7c3aed">{camp.listName}</Badge><Badge color={C.success}>Opens: {camp.openRate?.toFixed(1)}%</Badge><Badge color={C.primary}>Clicks: {camp.clickRate?.toFixed(1)}%</Badge></div></div><div style={{display:"flex",gap:6}}>{note&&<><DlBtn id={nid} name={`notes_${camp.name.replace(/[^a-zA-Z0-9]/g,"_")}`}/><button onClick={()=>{if(confirm("Remove notes?"))removeNote(camp.id)}} style={{display:"flex",alignItems:"center",gap:3,padding:"4px 8px",background:"#fef2f2",border:"1px solid #fecaca",borderRadius:6,fontSize:10,cursor:"pointer",color:C.danger,fontWeight:600}}><Trash2 size={11}/></button></>}<button onClick={()=>generateNotes(camp)} disabled={generating} style={{display:"flex",alignItems:"center",gap:4,padding:"8px 14px",background:generating?C.muted:`linear-gradient(135deg, ${C.primary}, ${C.secondary})`,color:"#fff",border:"none",borderRadius:9,fontSize:11,fontWeight:600,cursor:generating?"default":"pointer",whiteSpace:"nowrap"}}>{generating?<div style={{width:12,height:12,border:"2px solid rgba(255,255,255,.3)",borderTopColor:"#fff",borderRadius:"50%",animation:"spin .6s linear infinite"}}/>:<Brain size={13}/>}{note?"Regenerate":"Generate"}</button></div></div>{note?<div style={{animation:"slideUp .3s ease"}}><div style={{background:"#faf8fc",borderRadius:10,padding:14,marginBottom:10,borderLeft:`3px solid ${C.primary}`}}><h4 style={{fontSize:10,fontWeight:700,color:C.primary,marginBottom:5,textTransform:"uppercase"}}>Summary</h4><p style={{fontSize:12,color:C.dark,lineHeight:1.6}}>{note.summary}</p></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}><div style={{background:"#f7f5fa",borderRadius:10,padding:12}}><h4 style={{fontSize:10,fontWeight:700,color:C.secondary,marginBottom:6,textTransform:"uppercase"}}>Trends</h4>{note.trends?.map((t,j)=><div key={j} style={{display:"flex",gap:5,marginBottom:5,fontSize:11,color:C.dark,lineHeight:1.5}}><TrendingUp size={12} color={C.secondary} style={{marginTop:1,flexShrink:0}}/>{t}</div>)}</div><div style={{background:"#fef7f0",borderRadius:10,padding:12}}><h4 style={{fontSize:10,fontWeight:700,color:C.warning,marginBottom:6,textTransform:"uppercase"}}>Recommendations</h4>{note.recommendations?.map((r,j)=><div key={j} style={{display:"flex",gap:5,marginBottom:5,fontSize:11,color:C.dark,lineHeight:1.5}}><CheckCircle size={12} color={C.success} style={{marginTop:1,flexShrink:0}}/>{r}</div>)}</div></div></div>:<div style={{textAlign:"center",padding:"16px 0",color:C.muted}}><Brain size={24} style={{opacity:.2,marginBottom:4}}/><p style={{fontSize:11}}>Click "Generate" for AI insights</p></div>}</div>})}</div></div>}

// ========= TAB: CUSTOM ANALYSIS =========
function CustomAnalysisTab({campaigns,clickers}){const[sT,setST]=useState([]);const[sL,setSL]=useState([]);const[cf,setCf]=useState("company");const allL=[...new Set(campaigns.map(c=>c.listName).filter(Boolean))];const allT=[...new Set(campaigns.map(c=>c.type))];const tT=t=>setST(p=>p.includes(t)?p.filter(x=>x!==t):[...p,t]);const tL=l=>setSL(p=>p.includes(l)?p.filter(x=>x!==l):[...p,l]);const merged=useMemo(()=>{let c=[...campaigns];if(sT.length)c=c.filter(x=>sT.includes(x.type));if(sL.length)c=c.filter(x=>sL.includes(x.listName));return c},[campaigns,sT,sL]);const mCl=useMemo(()=>{const k=new Set(merged.map(c=>`${c.name}||${c.listName}`));return clickers.filter(c=>k.has(`${c.campaignName}||${c.listName}`))},[clickers,merged]);const tot={sends:0,opens:0,clicks:0};merged.forEach(c=>{tot.sends+=c.sends||0;tot.opens+=c.opens||0;tot.clicks+=c.clicks||0});const fd=useMemo(()=>{const m={};mCl.forEach(c=>{const v=c[cf];if(v)m[v]=(m[v]||0)+1});return Object.entries(m).sort((a,b)=>b[1]-a[1]).slice(0,10)},[mCl,cf]);const cd=merged.map(c=>({name:(c.name||"").slice(0,14),openRate:c.openRate||0,clickRate:c.clickRate||0}));
return <div style={{animation:"fadeIn .3s ease"}}><div style={{background:C.white,borderRadius:14,padding:18,border:"1px solid #f0ecf4",marginBottom:20}}><h3 style={{fontSize:13,fontWeight:700,color:C.dark,marginBottom:3}}>Custom Analysis - Merge and Compare</h3><p style={{fontSize:11,color:C.muted,marginBottom:14}}>Select types and/or lists to combine data.</p><div style={{marginBottom:12}}><label style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",display:"block",marginBottom:5}}>Types</label><div style={{display:"flex",gap:5,flexWrap:"wrap"}}>{allT.map(t=><button key={t} onClick={()=>tT(t)} style={{padding:"5px 12px",borderRadius:18,fontSize:11,fontWeight:600,cursor:"pointer",border:"1px solid",background:sT.includes(t)?C.primary:"transparent",color:sT.includes(t)?"#fff":C.dark,borderColor:sT.includes(t)?C.primary:"#ddd"}}>{t}</button>)}</div></div><div><label style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",display:"block",marginBottom:5}}>Lists</label><div style={{display:"flex",gap:5,flexWrap:"wrap"}}>{allL.map(l=><button key={l} onClick={()=>tL(l)} style={{padding:"5px 12px",borderRadius:18,fontSize:11,fontWeight:600,cursor:"pointer",border:"1px solid",background:sL.includes(l)?C.secondary:"transparent",color:sL.includes(l)?"#fff":C.dark,borderColor:sL.includes(l)?C.secondary:"#ddd"}}>{l}</button>)}</div></div></div>{merged.length===0?<Empty msg="Select types or lists above."/>:<><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit, minmax(160px, 1fr))",gap:12,marginBottom:20}}><KPI label="Campaigns" value={merged.length} icon={Layers} color={C.primary}/><KPI label="Open Rate" value={`${tot.sends>0?(tot.opens/tot.sends*100).toFixed(1):"0"}%`} icon={Mail} color={C.secondary}/><KPI label="Click Rate" value={`${tot.sends>0?(tot.clicks/tot.sends*100).toFixed(1):"0"}%`} icon={MousePointerClick} color="#7c3aed"/><KPI label="Contacts" value={mCl.length.toLocaleString()} icon={Users} color={C.bg1}/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:20}}><CC title="Comparison" id="cust-comp"><ResponsiveContainer width="100%" height={210}><BarChart data={cd}><CartesianGrid strokeDasharray="3 3" stroke="#f0ecf4"/><XAxis dataKey="name" fontSize={9} tick={{fill:C.muted}}/><YAxis fontSize={9} tick={{fill:C.muted}} tickFormatter={v=>`${v}%`}/><Tooltip contentStyle={{borderRadius:8,fontSize:11}} formatter={v=>`${v.toFixed(1)}%`}/><Legend fontSize={10}/><Bar dataKey="openRate" name="Open %" fill={C.primary} radius={[4,4,0,0]}/><Bar dataKey="clickRate" name="Click %" fill={C.secondary} radius={[4,4,0,0]}/></BarChart></ResponsiveContainer></CC><CC title="Merged Contacts" id="cust-cont" actions={<Sel value={cf} onChange={setCf} options={CF.map(f=>({value:f.key,label:f.label}))}/>}><ResponsiveContainer width="100%" height={210}><BarChart data={fd.map(([n,c])=>({name:n.slice(0,20),count:c}))} layout="vertical"><CartesianGrid strokeDasharray="3 3" stroke="#f0ecf4"/><XAxis type="number" fontSize={10} tick={{fill:C.muted}}/><YAxis dataKey="name" type="category" fontSize={9} tick={{fill:C.muted}} width={120}/><Tooltip contentStyle={{borderRadius:8,fontSize:11}}/><Bar dataKey="count" fill="#7c3aed" radius={[0,5,5,0]}/></BarChart></ResponsiveContainer></CC></div></>}</div>}

// ========= TAB: CUSTOM REPORTS =========
function CustomReportsTab({aiConfig}) {
  const [report, setReport] = useState(null);
  const [clickersData, setClickersData] = useState(null);
  const [screenshot, setScreenshot] = useState(null);
  const [aiNotes, setAiNotes] = useState(null);
  const [genAI, setGenAI] = useState(false);

  const handleReport = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target.result;
      if (isMailchimpReport(text)) {
        setReport(parseMailchimpReport(text));
      }
    };
    reader.readAsText(file);
  };

  const handleClickers = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const rows = parseCSV(e.target.result);
      setClickersData(rows.map(r => mapClickerRow(r)).filter(c => c.email));
    };
    reader.readAsText(file);
  };

  const handleScreenshot = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => setScreenshot({ data: e.target.result, name: file.name });
    reader.readAsDataURL(file);
  };

  const generateAI = async () => {
    if (!report) return;
    setGenAI(true);
    try {
      const prompt = `Analyze this email campaign briefly:\nTitle: ${report.title}\nSubject: ${report.subjectLine}\nSends: ${report.sends}, Opens: ${report.opens} (${report.openRate}%), Clicks: ${report.clicks} (${report.clickRate}%), Bounces: ${report.bounces}, Unsubs: ${report.unsubs}\n\nReturn JSON only: {"summary":"2-3 sentences","recommendations":["r1","r2","r3"]}`;
      let text = "";
      if (aiConfig.provider === "ollama") {
        const r = await fetch(aiConfig.ollamaUrl + "/api/generate", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: aiConfig.ollamaModel, prompt, stream: false }) });
        text = (await r.json()).response || "";
      } else {
        const h = { "Content-Type": "application/json" };
        if (aiConfig.apiKey) h["x-api-key"] = aiConfig.apiKey;
        const r = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: h, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, messages: [{ role: "user", content: prompt }] }) });
        text = (await r.json()).content?.map(c => c.text || "").join("") || "";
      }
      const cl = text.replace(/```json|```/g, "").trim();
      const jm = cl.match(/\{[\s\S]*\}/);
      setAiNotes(JSON.parse(jm ? jm[0] : cl));
    } catch (err) {
      console.error(err);
      setAiNotes({ summary: report.title + " achieved " + report.openRate + "% open rate and " + report.clickRate + "% click rate.", recommendations: ["Review subject line performance", "Optimize for engagement", "Monitor deliverability"] });
    }
    setGenAI(false);
  };

  const P = { dk: "#2d1a54", md: "#4225a6", lt: "#6b52c4", vlt: "#e8e0f7", bg: "#f5f2fc", white: "#fff", border: "#d4cbe8" };

  const reportHTML = () => {
    if (!report) return "";
    const r = report;
    const bRate = r.sends > 0 ? (r.bounces / r.sends * 100).toFixed(2) : "0";
    const uRate = r.sends > 0 ? (r.unsubs / r.sends * 100).toFixed(2) : "0";
    return `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
*{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',Segoe UI,sans-serif;background:#f5f2fc;padding:40px}
.page{max-width:700px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(45,26,84,.1)}
.hdr{background:linear-gradient(135deg,${P.dk},${P.md});padding:36px 40px;text-align:center;color:#fff}
.hdr h1{font-size:22px;font-weight:700;letter-spacing:1px;margin-bottom:4px}.hdr h2{font-size:13px;font-weight:400;opacity:.7;text-transform:uppercase;letter-spacing:2px}
.section{padding:0 40px}.section-title{background:${P.md};color:#fff;padding:10px 20px;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:1px;margin:24px -40px 0;width:calc(100% + 80px)}
.row{display:flex;justify-content:space-between;padding:10px 0;border-bottom:1px solid ${P.vlt};font-size:13px}.row .label{color:${P.dk};font-weight:600}.row .val{color:${P.md};font-weight:700}
.group-title{background:${P.vlt};color:${P.dk};padding:8px 20px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;margin:0 -40px;width:calc(100% + 80px)}
table{width:100%;border-collapse:collapse;margin:12px 0}th{background:${P.dk};color:#fff;padding:10px 16px;text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.5px}td{padding:10px 16px;border-bottom:1px solid ${P.vlt};font-size:12px;color:${P.dk}}tr:hover td{background:${P.bg}}
.ai-box{background:${P.bg};border-left:4px solid ${P.md};padding:16px 20px;margin:16px 0;border-radius:0 8px 8px 0}.ai-box h4{color:${P.md};font-size:11px;text-transform:uppercase;margin-bottom:8px}.ai-box p{font-size:12px;line-height:1.6;color:${P.dk}}.ai-box li{font-size:12px;line-height:1.8;color:${P.dk}}
.footer{text-align:center;padding:20px 40px;color:${P.md};font-size:10px;border-top:1px solid ${P.vlt}}
.screenshot{text-align:center;padding:20px 0}img.email-img{max-width:100%;border-radius:8px;border:1px solid ${P.border}}
</style></head><body><div class="page">
<div class="hdr"><h1>${r.title || "Campaign Report"}</h1><h2>Email Campaign Report</h2></div>
<div class="section">
<div class="section-title">Campaign Details</div>
<div class="row"><span class="label">Subject Line</span><span class="val">${r.subjectLine}</span></div>
<div class="row"><span class="label">Send Date and Time</span><span class="val">${r.date}</span></div>

<div class="group-title">Core Metrics</div>
<div class="row"><span class="label">Total Recipients</span><span class="val">${r.sends?.toLocaleString()}</span></div>
<div class="row"><span class="label">Successful Deliveries</span><span class="val">${r.delivered?.toLocaleString()}</span></div>

<div class="group-title">Engagement</div>
<div class="row"><span class="label">Unique Opens and Open Rate</span><span class="val">${r.opens?.toLocaleString()} (${r.openRate}%)</span></div>
<div class="row"><span class="label">Total Opens</span><span class="val">${r.totalOpens?.toLocaleString()}</span></div>
<div class="row"><span class="label">Unique Clicks and Click Rate</span><span class="val">${r.clicks?.toLocaleString()} (${r.clickRate}%)</span></div>
<div class="row"><span class="label">Total Clicks</span><span class="val">${r.totalClicks?.toLocaleString()}</span></div>

<div class="group-title">Issues</div>
<div class="row"><span class="label">Bounces</span><span class="val">${r.bounces?.toLocaleString()} (${r.bounceRate || bRate}%)</span></div>
<div class="row"><span class="label">Unsubscribes</span><span class="val">${r.unsubs} (${uRate}%)</span></div>

${r.urlClicks?.length ? `<div class="section-title">Clicks by URL</div><table><thead><tr><th>URL</th><th>Total Clicks</th><th>Unique Clicks</th></tr></thead><tbody>${r.urlClicks.map(u => `<tr><td style="max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${u.url}</td><td>${u.totalClicks}</td><td>${u.uniqueClicks}</td></tr>`).join("")}</tbody></table>` : ""}

${clickersData?.length ? `<div class="section-title">Clickers (${clickersData.length})</div><table><thead><tr><th>Email</th><th>Name</th><th>Company</th><th>State</th></tr></thead><tbody>${clickersData.slice(0, 30).map(c => `<tr><td>${c.email}</td><td>${c.firstName} ${c.lastName}</td><td>${c.company}</td><td>${c.state}</td></tr>`).join("")}</tbody></table>${clickersData.length > 30 ? `<p style="text-align:center;padding:8px;color:${P.md};font-size:11px">Showing 30 of ${clickersData.length} clickers</p>` : ""}` : ""}

${aiNotes ? `<div class="section-title">AI Insights</div><div class="ai-box"><h4>Summary</h4><p>${aiNotes.summary}</p></div><div class="ai-box"><h4>Recommendations</h4><ul>${(aiNotes.recommendations || []).map(r => `<li>${r}</li>`).join("")}</ul></div>` : ""}

${screenshot ? `<div class="section-title">Email Preview</div><div class="screenshot"><img class="email-img" src="${screenshot.data}" alt="Email Preview"/></div>` : ""}
</div>
<div class="footer">Email Campaign Analytics by kenn.d</div>
</div></body></html>`;
  };

  const downloadHTML = () => {
    const html = reportHTML();
    const blob = new Blob([html], { type: "text/html" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = (report?.title || "report").replace(/[^a-zA-Z0-9]/g, "_") + ".html";
    a.click();
  };

  const downloadReportCSV = () => {
    if (!report) return;
    const r = report;
    const rows = [["Field", "Value"], ["Title", r.title], ["Subject Line", r.subjectLine], ["Date", r.date], ["Total Recipients", r.sends], ["Successful Deliveries", r.delivered], ["Unique Opens", r.opens], ["Open Rate", r.openRate + "%"], ["Total Opens", r.totalOpens], ["Unique Clicks", r.clicks], ["Click Rate", r.clickRate + "%"], ["Total Clicks", r.totalClicks], ["Bounces", r.bounces], ["Unsubscribes", r.unsubs]];
    if (r.urlClicks?.length) { rows.push(["", ""]); rows.push(["URL", "Total Clicks", "Unique Clicks"]); r.urlClicks.forEach(u => rows.push([u.url, u.totalClicks, u.uniqueClicks])); }
    downloadCSVData(rows[0], rows.slice(1), (r.title || "report").replace(/[^a-zA-Z0-9]/g, "_"));
  };

  const downloadReportPNG = () => downloadPNG("custom-report-preview", (report?.title || "report").replace(/[^a-zA-Z0-9]/g, "_"));

  return (
    <div style={{ animation: "fadeIn .3s ease" }}>
      {/* Upload Section */}
      <div style={{ background: C.white, borderRadius: 14, padding: 22, border: "1px solid #f0ecf4", marginBottom: 20 }}>
        <h3 style={{ fontSize: 14, fontWeight: 700, color: C.dark, marginBottom: 4 }}>Generate Custom Report</h3>
        <p style={{ fontSize: 11, color: C.muted, marginBottom: 16 }}>Upload a Mailchimp campaign report to generate a polished, shareable report. Add clicker data, screenshots, and AI notes.</p>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginBottom: 16 }}>
          <DropZone label="Campaign Report (CSV)" onFile={handleReport} loaded={!!report} count={report ? 1 : 0} />
          <DropZone label="Clickers Data (CSV)" onFile={handleClickers} loaded={!!clickersData} count={clickersData?.length} />
          <div>
            <div onClick={() => document.getElementById("cr-screenshot")?.click()} style={{ border: "2px dashed " + (screenshot ? C.success : "#ddd"), borderRadius: 12, padding: "22px 20px", textAlign: "center", cursor: "pointer", background: screenshot ? C.success + "08" : "#faf8fc" }}>
              <input id="cr-screenshot" type="file" accept="image/*" style={{ display: "none" }} onChange={e => e.target.files[0] && handleScreenshot(e.target.files[0])} />
              {screenshot ? <><CheckCircle size={20} color={C.success} style={{ marginBottom: 4 }} /><p style={{ fontSize: 12, fontWeight: 600, color: C.success }}>Screenshot added</p></> : <><Image size={20} color={C.muted} style={{ marginBottom: 4 }} /><p style={{ fontSize: 12, fontWeight: 600, color: C.dark }}>Email Screenshot</p><p style={{ fontSize: 10, color: C.muted, marginTop: 2 }}>Optional</p></>}
            </div>
          </div>
        </div>
        {report && (
          <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap" }}>
            <button onClick={generateAI} disabled={genAI} style={{ display: "flex", alignItems: "center", gap: 4, padding: "8px 16px", background: genAI ? C.muted : "linear-gradient(135deg, " + C.primary + ", " + C.secondary + ")", color: "#fff", border: "none", borderRadius: 9, fontSize: 11, fontWeight: 600, cursor: genAI ? "default" : "pointer" }}>
              {genAI ? <div style={{ width: 12, height: 12, border: "2px solid rgba(255,255,255,.3)", borderTopColor: "#fff", borderRadius: "50%", animation: "spin .6s linear infinite" }} /> : <Brain size={13} />}
              {aiNotes ? "Regenerate AI Notes" : "Generate AI Notes"}
            </button>
            <div style={{ flex: 1 }} />
            <button onClick={downloadHTML} style={{ display: "flex", alignItems: "center", gap: 4, padding: "8px 14px", background: C.secondary, color: "#fff", border: "none", borderRadius: 8, fontSize: 11, fontWeight: 600, cursor: "pointer" }}><Download size={12} /> HTML</button>
            <button onClick={downloadReportCSV} style={{ display: "flex", alignItems: "center", gap: 4, padding: "8px 14px", background: "#f5f2f8", border: "1px solid #e8e4ee", borderRadius: 8, fontSize: 11, fontWeight: 600, cursor: "pointer", color: C.dark }}><Download size={12} /> CSV</button>
            <button onClick={downloadReportPNG} style={{ display: "flex", alignItems: "center", gap: 4, padding: "8px 14px", background: "#f5f2f8", border: "1px solid #e8e4ee", borderRadius: 8, fontSize: 11, fontWeight: 600, cursor: "pointer", color: C.dark }}><Download size={12} /> PNG</button>
          </div>
        )}
      </div>

      {/* Report Preview */}
      {report ? (
        <div id="custom-report-preview" style={{ background: C.white, borderRadius: 14, overflow: "hidden", border: "1px solid #d4cbe8", boxShadow: "0 4px 24px rgba(45,26,84,.08)" }}>
          {/* Header */}
          <div style={{ background: "linear-gradient(135deg, #2d1a54, #4225a6)", padding: "32px 40px", textAlign: "center", color: "#fff" }}>
            <h2 style={{ fontSize: 20, fontWeight: 700, letterSpacing: 1, marginBottom: 4 }}>{report.title || "Campaign Report"}</h2>
            <p style={{ fontSize: 12, opacity: .7, textTransform: "uppercase", letterSpacing: 2 }}>Email Campaign Report</p>
          </div>

          <div style={{ padding: "0 40px 30px" }}>
            {/* Campaign Details */}
            <div style={{ background: "#4225a6", color: "#fff", padding: "10px 20px", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, margin: "24px -40px 0", width: "calc(100% + 80px)" }}>Campaign Details</div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "12px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Subject Line</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.subjectLine}</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "12px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Send Date and Time</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.date}</span></div>

            {/* Core Metrics */}
            <div style={{ background: "#e8e0f7", color: "#2d1a54", padding: "8px 20px", fontSize: 11, fontWeight: 700, textTransform: "uppercase", margin: "16px -40px 0", width: "calc(100% + 80px)" }}>Core Metrics</div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Total Recipients</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.sends?.toLocaleString()}</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Successful Deliveries</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.delivered?.toLocaleString()}</span></div>

            {/* Engagement */}
            <div style={{ background: "#e8e0f7", color: "#2d1a54", padding: "8px 20px", fontSize: 11, fontWeight: 700, textTransform: "uppercase", margin: "16px -40px 0", width: "calc(100% + 80px)" }}>Engagement</div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Unique Opens and Open Rate</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.opens?.toLocaleString()} ({report.openRate}%)</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Total Opens</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.totalOpens?.toLocaleString()}</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Unique Clicks and Click Rate</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.clicks?.toLocaleString()} ({report.clickRate}%)</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Total Clicks</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.totalClicks?.toLocaleString()}</span></div>

            {/* Issues */}
            <div style={{ background: "#e8e0f7", color: "#2d1a54", padding: "8px 20px", fontSize: 11, fontWeight: 700, textTransform: "uppercase", margin: "16px -40px 0", width: "calc(100% + 80px)" }}>Issues</div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Bounces</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.bounces?.toLocaleString()} ({report.bounceRate}%)</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #e8e0f7", fontSize: 13 }}><span style={{ color: "#2d1a54", fontWeight: 600 }}>Unsubscribes</span><span style={{ color: "#4225a6", fontWeight: 700 }}>{report.unsubs}</span></div>

            {/* Clicks by URL */}
            {report.urlClicks?.length > 0 && <>
              <div style={{ background: "#2d1a54", color: "#fff", padding: "10px 20px", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, margin: "24px -40px 0", width: "calc(100% + 80px)" }}>Clicks by URL</div>
              <table style={{ width: "100%", borderCollapse: "collapse", marginTop: 12 }}>
                <thead><tr><th style={{ background: "#2d1a54", color: "#fff", padding: "10px 16px", textAlign: "left", fontSize: 11, textTransform: "uppercase" }}>URL</th><th style={{ background: "#2d1a54", color: "#fff", padding: "10px 16px", textAlign: "left", fontSize: 11 }}>Total Clicks</th><th style={{ background: "#2d1a54", color: "#fff", padding: "10px 16px", textAlign: "left", fontSize: 11 }}>Unique Clicks</th></tr></thead>
                <tbody>{report.urlClicks.map((u, i) => <tr key={i}><td style={{ padding: "10px 16px", borderBottom: "1px solid #e8e0f7", fontSize: 12, color: "#2d1a54", maxWidth: 300, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{u.url}</td><td style={{ padding: "10px 16px", borderBottom: "1px solid #e8e0f7", fontSize: 12, fontWeight: 600, color: "#4225a6" }}>{u.totalClicks}</td><td style={{ padding: "10px 16px", borderBottom: "1px solid #e8e0f7", fontSize: 12, fontWeight: 600, color: "#4225a6" }}>{u.uniqueClicks}</td></tr>)}</tbody>
              </table>
            </>}

            {/* Clickers */}
            {clickersData?.length > 0 && <>
              <div style={{ background: "#4225a6", color: "#fff", padding: "10px 20px", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, margin: "24px -40px 0", width: "calc(100% + 80px)" }}>Clickers ({clickersData.length})</div>
              <table style={{ width: "100%", borderCollapse: "collapse", marginTop: 12 }}>
                <thead><tr>{["Email", "Name", "Company", "State", "Career Level"].map(h => <th key={h} style={{ background: "#2d1a54", color: "#fff", padding: "8px 12px", textAlign: "left", fontSize: 10, textTransform: "uppercase" }}>{h}</th>)}</tr></thead>
                <tbody>{clickersData.slice(0, 30).map((c, i) => <tr key={i}><td style={{ padding: "8px 12px", borderBottom: "1px solid #e8e0f7", fontSize: 11, color: "#4225a6" }}>{c.email}</td><td style={{ padding: "8px 12px", borderBottom: "1px solid #e8e0f7", fontSize: 11 }}>{c.firstName} {c.lastName}</td><td style={{ padding: "8px 12px", borderBottom: "1px solid #e8e0f7", fontSize: 11 }}>{c.company}</td><td style={{ padding: "8px 12px", borderBottom: "1px solid #e8e0f7", fontSize: 11 }}>{c.state}</td><td style={{ padding: "8px 12px", borderBottom: "1px solid #e8e0f7", fontSize: 11 }}>{c.careerLevel}</td></tr>)}</tbody>
              </table>
              {clickersData.length > 30 && <p style={{ textAlign: "center", padding: 8, color: "#4225a6", fontSize: 10 }}>Showing 30 of {clickersData.length} clickers</p>}
            </>}

            {/* AI Notes */}
            {aiNotes && <>
              <div style={{ background: "#4225a6", color: "#fff", padding: "10px 20px", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, margin: "24px -40px 0", width: "calc(100% + 80px)" }}>AI Insights</div>
              <div style={{ background: "#f5f2fc", borderLeft: "4px solid #4225a6", padding: "16px 20px", margin: "16px 0", borderRadius: "0 8px 8px 0" }}>
                <h4 style={{ color: "#4225a6", fontSize: 11, textTransform: "uppercase", marginBottom: 8 }}>Summary</h4>
                <p style={{ fontSize: 12, lineHeight: 1.6, color: "#2d1a54" }}>{aiNotes.summary}</p>
              </div>
              <div style={{ background: "#f5f2fc", borderLeft: "4px solid #6b52c4", padding: "16px 20px", margin: "8px 0", borderRadius: "0 8px 8px 0" }}>
                <h4 style={{ color: "#4225a6", fontSize: 11, textTransform: "uppercase", marginBottom: 8 }}>Recommendations</h4>
                {aiNotes.recommendations?.map((r, i) => <div key={i} style={{ display: "flex", gap: 6, marginBottom: 4, fontSize: 12, color: "#2d1a54" }}><CheckCircle size={12} color="#4225a6" style={{ marginTop: 2, flexShrink: 0 }} />{r}</div>)}
              </div>
            </>}

            {/* Screenshot */}
            {screenshot && <>
              <div style={{ background: "#4225a6", color: "#fff", padding: "10px 20px", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, margin: "24px -40px 0", width: "calc(100% + 80px)" }}>Email Preview</div>
              <div style={{ textAlign: "center", padding: "20px 0" }}><img src={screenshot.data} alt="Email Preview" style={{ maxWidth: "100%", borderRadius: 8, border: "1px solid #d4cbe8" }} /></div>
            </>}
          </div>

          <div style={{ textAlign: "center", padding: "16px 40px", color: "#4225a6", fontSize: 10, borderTop: "1px solid #e8e0f7" }}>Email Campaign Analytics by kenn.d</div>
        </div>
      ) : (
        <Empty msg="Upload a Mailchimp campaign report above to generate a custom report." />
      )}
    </div>
  );
}

// ========= UPLOAD MODAL =========
function UploadModal({onClose,addCampaign,addClickers}){
  const[step,setStep]=useState(1);const[cn,setCn]=useState("");const[ct,setCt]=useState(CAMPAIGN_TYPES[0]);const[ln,setLn]=useState("");const[cp,setCp]=useState(null);const[cd,setCd]=useState(null);const[ck,setCk]=useState(null);const[parsing,setParsing]=useState(false);const[result,setResult]=useState(null);
  const handleFile=(file,target)=>{const reader=new FileReader();reader.onload=e=>{const text=e.target.result;if(target==="campaign"){if(ct==="Pub Comms"&&isPubCommsCSV(text)){const rows=parseCSV(text);const parsed=parsePubCommsCSV(rows);setCp({_isPubComms:true,campaigns:parsed});setCd(null);if(!cn&&parsed.length>0){const common=parsed[0].name.split(" - ").slice(0,-1).join(" - ");setCn(common||parsed[0].name)}}else if(isMailchimpReport(text)){const p=parseMailchimpReport(text);setCp(p);setCd(null);if(!cn&&p.title)setCn(p.title)}else{setCd(parseCSV(text));setCp(null)}}else{setCk(parseCSV(text))}};reader.readAsText(file)};

  const process=()=>{setParsing(true);setTimeout(()=>{let processed=0;const useName=cn||cp?.title||"Untitled";const useList=ln||"Default";
    if(cp?._isPubComms){cp.campaigns.forEach(pc=>{addCampaign({name:pc.name,type:"Pub Comms",listName:useList,sends:pc.sends,opens:pc.opens,openRate:pc.openRate,clicks:pc.clicks,clickRate:pc.clickRate,totalClicks:pc.totalClicks,bounces:pc.bounces,bounceRate:pc.bounceRate,unsubs:pc.unsubs,date:pc.date});processed++})}
    else if(cp?._isMailchimpReport){const p=cp;addCampaign({name:useName,type:ct,listName:useList,subjectLine:p.subjectLine,sends:p.sends,delivered:p.delivered,opens:p.opens,totalOpens:p.totalOpens,clicks:p.clicks,totalClicks:p.totalClicks,bounces:p.bounces,unsubs:p.unsubs,openRate:p.openRate,clickRate:p.clickRate,bounceRate:p.bounceRate,date:p.date||new Date().toISOString().slice(0,10),urlClicks:p.urlClicks||[]});processed++}
    else if(cd?.length>0){const keys=Object.keys(cd[0]);const fc=pats=>keys.find(k=>pats.some(p=>k.toLowerCase().includes(p)))||null;const rows=ct==="Pub Comms"&&cd.length>1?cd:[cd[0]];rows.forEach(row=>{addCampaign({name:cleanVal(row[fc(["campaign","name","subject"])])||useName,type:ct,listName:useList,sends:parseInt((row[fc(["sent","send","recipients"])]||"0").replace(/,/g,""),10),opens:parseInt((row[fc(["open","unique open"])]||"0").replace(/,/g,""),10),clicks:parseInt((row[fc(["click","unique click"])]||"0").replace(/,/g,""),10),bounces:parseInt((row[fc(["bounce"])]||"0").replace(/,/g,""),10),unsubs:parseInt((row[fc(["unsub"])]||"0").replace(/,/g,""),10),openRate:parseFloat((row[fc(["open rate"])]||"0").replace("%","")),clickRate:parseFloat((row[fc(["click rate"])]||"0").replace("%","")),bounceRate:parseFloat((row[fc(["bounce rate"])]||"0").replace("%","")),date:row[fc(["date","send date"])]||new Date().toISOString().slice(0,10)});processed++})}
    let cc=0;if(ck?.length>0){const mapped=ck.map(row=>mapClickerRow(row)).filter(c=>c.email);addClickers(mapped,useName,useList);cc=mapped.length}
    setResult({campaigns:processed,clickers:cc});setParsing(false);setStep(3)},500)};

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,backdropFilter:"blur(4px)"}} onClick={onClose}><div onClick={e=>e.stopPropagation()} style={{background:C.white,borderRadius:18,width:"92%",maxWidth:560,maxHeight:"92vh",overflow:"auto",animation:"slideUp .3s ease"}}><div style={{padding:"18px 22px",borderBottom:"1px solid #f0ecf4",display:"flex",justifyContent:"space-between",alignItems:"center"}}><h2 style={{fontSize:16,fontWeight:700,color:C.dark}}>Upload Campaign Data</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={17}/></button></div><div style={{padding:22}}>
  {step===1&&<><div style={{marginBottom:16}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>Campaign Name <span style={{fontWeight:400,textTransform:"none"}}>(auto-detected)</span></label><input value={cn} onChange={e=>setCn(e.target.value)} placeholder="Auto-filled from report" style={{width:"100%",padding:"10px 12px",borderRadius:9,border:"1px solid #e8e4ee",fontSize:12,outline:"none"}}/></div><div style={{marginBottom:16}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>Campaign Type</label><select value={ct} onChange={e=>{setCt(e.target.value);setLn("")}} style={{width:"100%",padding:"10px 12px",borderRadius:9,border:"1px solid #e8e4ee",fontSize:12,outline:"none",background:"#fff"}}>{CAMPAIGN_TYPES.map(t=><option key={t} value={t}>{t}</option>)}</select></div><div style={{marginBottom:20}}><label style={{display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:4,textTransform:"uppercase"}}>List Name</label><ListPicker campaignType={ct} value={ln} onChange={setLn}/></div>{ct==="Pub Comms"&&<div style={{background:"#f0f7ff",borderRadius:8,padding:12,marginBottom:16,border:"1px solid #bfdbfe"}}><p style={{fontSize:11,color:"#1e40af"}}>Pub Comms reports with multiple rows (Serial Number, Campaign, Date Sent...) are auto-detected and each row is imported as a separate campaign for logging.</p></div>}<button onClick={()=>setStep(2)} style={{width:"100%",padding:"11px",background:C.primary,color:"#fff",border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:"pointer"}}>Continue</button></>}
  {step===2&&<><DropZone label="Campaign Report (CSV)" onFile={f=>handleFile(f,"campaign")} loaded={!!(cp||cd)} count={cp?._isPubComms?cp.campaigns.length:(cp?1:cd?.length)}/>{cp?._isPubComms&&<div style={{margin:"8px 0",padding:10,background:"#f0f7ff",borderRadius:8,fontSize:10,border:"1px solid #bfdbfe"}}><div style={{fontWeight:700,marginBottom:4,color:"#1e40af",textTransform:"uppercase"}}>Pub Comms - {cp.campaigns.length} campaigns detected</div>{cp.campaigns.slice(0,5).map((pc,i)=><div key={i} style={{fontSize:10,color:C.dark,padding:"2px 0"}}>{pc.name} - Sent: {pc.date}</div>)}{cp.campaigns.length>5&&<p style={{color:C.muted}}>+{cp.campaigns.length-5} more</p>}</div>}{cp&&!cp._isPubComms&&<div style={{margin:"8px 0",padding:10,background:"#f7f5fa",borderRadius:8,fontSize:10,border:`1px solid ${C.bg3}`}}><div style={{fontWeight:700,marginBottom:4,color:C.secondary,textTransform:"uppercase"}}>Mailchimp Report Detected</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"3px 12px"}}><span><b>Title:</b> {cp.title}</span><span><b>Subject:</b> {(cp.subjectLine||"").slice(0,35)}</span><span><b>Recipients:</b> {cp.sends?.toLocaleString()}</span><span><b>Opens:</b> {cp.opens?.toLocaleString()} ({cp.openRate}%)</span><span><b>Clicks:</b> {cp.clicks?.toLocaleString()} ({cp.clickRate}%)</span><span><b>Unsubs:</b> {cp.unsubs}</span></div></div>}<div style={{height:10}}/>{ct!=="Pub Comms"&&<DropZone label="Clickers Data (CSV)" onFile={f=>handleFile(f,"clickers")} loaded={!!ck} count={ck?.length}/>}<div style={{display:"flex",gap:8,marginTop:18}}><button onClick={()=>setStep(1)} style={{flex:1,padding:"10px",background:"#f5f2f8",color:C.dark,border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:"pointer"}}>Back</button><button onClick={process} disabled={!cp&&!cd&&!ck} style={{flex:2,padding:"10px",background:(cp||cd||ck)?C.primary:"#ccc",color:"#fff",border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:(cp||cd||ck)?"pointer":"default"}}>{parsing?"Processing...":"Import"}</button></div></>}
  {step===3&&result&&<div style={{textAlign:"center",padding:"14px 0"}}><div style={{width:48,height:48,borderRadius:"50%",background:C.success+"18",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 12px"}}><CheckCircle size={24} color={C.success}/></div><h3 style={{fontSize:16,fontWeight:700,color:C.dark,marginBottom:5}}>Import Complete!</h3><p style={{fontSize:12,color:C.muted,marginBottom:16}}>{result.campaigns} campaign(s) and {result.clickers} clicker(s) imported.</p><button onClick={onClose} style={{padding:"10px 24px",background:C.primary,color:"#fff",border:"none",borderRadius:9,fontSize:12,fontWeight:600,cursor:"pointer"}}>Done</button></div>}
  </div></div></div>}
